import { useState, useEffect } from "react";
import { supabase } from "../services/supabaseClient";
import { useNavigate } from "react-router-dom";

export default function Profile({ user, setUser }) {
  const [loading, setLoading] = useState(false);
  const [profile, setProfile] = useState({
    name: "",
    phone: "",
    gender: "",
    city: "",
    state: "",
    email: ""
  });
  const navigate = useNavigate();

  useEffect(() => {
    if (user) {
      setProfile({
        name: user.user_metadata?.name || "",
        phone: user.user_metadata?.phone || "",
        gender: user.user_metadata?.gender || "",
        city: user.user_metadata?.city || "",
        state: user.user_metadata?.state || "",
        email: user.email
      });
    }
  }, [user]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    const updates = {
      name: profile.name,
      phone: profile.phone,
      gender: profile.gender,
      city: profile.city,
      state: profile.state,
    };

    const { error } = await supabase.auth.updateUser({ 
      data: updates 
    });

    setLoading(false);
    if (error) {
      alert(error.message);
    } else {
      alert("Profile updated!");
      setUser({ ...user, user_metadata: updates });
      navigate(-1);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-slate-50 via-blue-50 to-indigo-100 dark:from-gray-900 dark:via-slate-900 dark:to-gray-950 p-4">
      <div className="backdrop-blur-lg bg-white/80 dark:bg-gray-800/80 border border-white/40 dark:border-gray-600 p-8 rounded-2xl shadow-2xl max-w-md w-full">
        <h2 className="text-2xl font-bold text-center mb-6 text-gray-800 dark:text-gray-200">
          Edit Profile
        </h2>
        <form onSubmit={handleSubmit}>
          <input
            type="text"
            placeholder="Full Name"
            className="w-full p-3 mb-3 rounded-lg bg-white/90 dark:bg-gray-700/90 border border-white/50 dark:border-gray-600 focus:outline-none focus:ring-2 focus:ring-indigo-400 dark:focus:ring-indigo-500 text-gray-800 dark:text-gray-200 placeholder-gray-500 dark:placeholder-gray-400"
            value={profile.name}
            onChange={(e) => setProfile({...profile, name: e.target.value})}
          />
          <input
            type="tel"
            placeholder="Phone Number"
            className="w-full p-3 mb-3 rounded-lg bg-white/90 dark:bg-gray-700/90 border border-white/50 dark:border-gray-600 focus:outline-none focus:ring-2 focus:ring-indigo-400 dark:focus:ring-indigo-500 text-gray-800 dark:text-gray-200 placeholder-gray-500 dark:placeholder-gray-400"
            value={profile.phone}
            onChange={(e) => setProfile({...profile, phone: e.target.value})}
          />
          <select
            className="w-full p-3 mb-3 rounded-lg bg-white/90 dark:bg-gray-700/90 border border-white/50 dark:border-gray-600 focus:outline-none focus:ring-2 focus:ring-indigo-400 dark:focus:ring-indigo-500 text-gray-800 dark:text-gray-200"
            value={profile.gender}
            onChange={(e) => setProfile({...profile, gender: e.target.value})}
          >
            <option value="">Gender</option>
            <option value="male">Male</option>
            <option value="female">Female</option>
            <option value="other">Other</option>
          </select>
          <input
            type="text"
            placeholder="City"
            className="w-full p-3 mb-3 rounded-lg bg-white/90 dark:bg-gray-700/90 border border-white/50 dark:border-gray-600 focus:outline-none focus:ring-2 focus:ring-indigo-400 dark:focus:ring-indigo-500 text-gray-800 dark:text-gray-200 placeholder-gray-500 dark:placeholder-gray-400"
            value={profile.city}
            onChange={(e) => setProfile({...profile, city: e.target.value})}
          />
          <input
            type="text"
            placeholder="State"
            className="w-full p-3 mb-3 rounded-lg bg-white/90 dark:bg-gray-700/90 border border-white/50 dark:border-gray-600 focus:outline-none focus:ring-2 focus:ring-indigo-400 dark:focus:ring-indigo-500 text-gray-800 dark:text-gray-200 placeholder-gray-500 dark:placeholder-gray-400"
            value={profile.state}
            onChange={(e) => setProfile({...profile, state: e.target.value})}
          />
          <input
            type="email"
            placeholder="Email"
            className="w-full p-3 mb-4 rounded-lg bg-white/90 dark:bg-gray-700/90 border border-white/50 dark:border-gray-600 focus:outline-none focus:ring-2 focus:ring-indigo-400 dark:focus:ring-indigo-500 opacity-70 text-gray-800 dark:text-gray-200"
            value={profile.email}
            readOnly
          />
          <button
            type="submit"
            disabled={loading}
            className="w-full bg-gradient-to-r from-indigo-600 to-purple-600 text-white py-3 rounded-lg hover:from-indigo-700 hover:to-purple-700 transition-all duration-300 font-semibold shadow-lg hover:shadow-xl disabled:opacity-50"
          >
            {loading ? "Saving..." : "Save Profile"}
          </button>
        </form>
      </div>
    </div>
  );
}
